import { useEffect, useState } from "react";
import API from "../api/axios";
import { useNavigate } from "react-router-dom";
import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Legend
} from "recharts";

function Dashboard() {

  const navigate = useNavigate();

  const [data, setData] = useState(null);
  const [budgetInput, setBudgetInput] = useState("");

  // ================= FETCH DASHBOARD =================
  const fetchDashboard = async () => {
    try {
      const res = await API.get("/dashboard");
      setData(res.data);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    fetchDashboard();
  }, []);

  // ================= SAVE BUDGET =================
  const handleBudgetSubmit = async (e) => {
    e.preventDefault();

    try {
      await API.post("/budget", {
        amount: budgetInput
      });

      alert("Budget Saved ✅");
      setBudgetInput("");

      fetchDashboard(); // refresh dashboard

    } catch (err) {
      console.log(err);
    }
  };

  if (!data) return <h2>Loading...</h2>;

  // ================= PIE DATA =================
  const pieData = [
    { name: "Income", value: data.totalIncome },
    { name: "Expense", value: data.totalExpense }
  ];

  const COLORS = ["#28a745", "#dc3545"];

  // ================= BAR DATA =================
  const barData = data.monthlyData.map(item => ({
    month: `Month ${item._id.month}`,
    total: item.total
  }));

  // ================= BUDGET PERCENT =================
  const percentUsed =
    data.budget > 0
      ? Math.min((data.totalExpense / data.budget) * 100, 100)
      : 0;

  return (
    <div style={{ padding: "20px" }}>
      <h2>Dashboard</h2>

      {/* ===== NAVIGATION ===== */}
      <button
        onClick={() => navigate("/transactions")}
        style={{ padding: "10px 15px", marginTop: "10px", cursor: "pointer" }}
      >
        Manage Transactions
      </button>

      {/* ===== BUDGET INPUT ===== */}
      <form onSubmit={handleBudgetSubmit} style={{ marginTop: "15px" }}>
        <input
          type="number"
          placeholder="Set Monthly Budget"
          value={budgetInput}
          onChange={(e) => setBudgetInput(e.target.value)}
          style={{ padding: "8px" }}
        />

        <button style={{ marginLeft: "10px" }}>
          Save Budget
        </button>
      </form>

      {/* ===== ALERT ===== */}
      {data.exceeded && (
        <div
          style={{
            backgroundColor: "#ffcccc",
            padding: "10px",
            marginTop: "15px",
            borderRadius: "5px"
          }}
        >
          ⚠️ Budget exceeded this month!
        </div>
      )}

      {/* ===== CARDS ===== */}
      <div style={{ display: "flex", gap: "20px", marginTop: "20px" }}>
        <div style={cardStyle}>
          <h3>Balance</h3>
          <p>₹ {data.balance}</p>
        </div>

        <div style={{ ...cardStyle, backgroundColor: "#d4edda" }}>
          <h3>Income</h3>
          <p>₹ {data.totalIncome}</p>
        </div>

        <div style={{ ...cardStyle, backgroundColor: "#f8d7da" }}>
          <h3>Expense</h3>
          <p>₹ {data.totalExpense}</p>
        </div>

        <div style={{ ...cardStyle, backgroundColor: "#fff3cd" }}>
          <h3>Monthly Budget</h3>
          <p>₹ {data.budget}</p>
        </div>
      </div>

      {/* ===== BUDGET PROGRESS ===== */}
      <div style={{ marginTop: "25px" }}>
        <h3>Budget Usage</h3>

        <div
          style={{
            background: "#ddd",
            height: "20px",
            borderRadius: "10px"
          }}
        >
          <div
            style={{
              width: `${percentUsed}%`,
              background: data.exceeded ? "red" : "green",
              height: "100%",
              borderRadius: "10px",
              transition: "0.4s"
            }}
          />
        </div>

        <p>
          ₹ {data.totalExpense} / ₹ {data.budget}
        </p>
      </div>

      {/* ===== CHARTS ===== */}
      <div style={{ display: "flex", gap: "50px", marginTop: "40px" }}>

        {/* PIE */}
        <div>
          <h3>Income vs Expense</h3>
          <PieChart width={300} height={300}>
            <Pie
              data={pieData}
              cx="50%"
              cy="50%"
              outerRadius={100}
              dataKey="value"
              label
            >
              {pieData.map((entry, index) => (
                <Cell key={index} fill={COLORS[index]} />
              ))}
            </Pie>
            <Tooltip />
          </PieChart>
        </div>

        {/* BAR */}
        <div>
          <h3>Monthly Expenses</h3>
          <BarChart width={400} height={300} data={barData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="month" />
            <YAxis />
            <Tooltip />
            <Legend />
            <Bar dataKey="total" fill="#007bff" />
          </BarChart>
        </div>

      </div>
    </div>
  );
}

const cardStyle = {
  flex: 1,
  padding: "20px",
  borderRadius: "10px",
  backgroundColor: "#e2e3e5",
  textAlign: "center",
  boxShadow: "0 2px 8px rgba(0,0,0,0.1)"
};

export default Dashboard;
